// Validation helper module

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validates a URL/query parameter ID.
 * Accepts string representations of positive integers (e.g. req.params.id).
 * Returns an array of error strings (empty = valid).
 */
function validateParamId(params) {
  const errors = [];
  const { id } = params;

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
  } else if (!/^\d+$/.test(String(id)) || Number(id) <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validates a name value.
 * Rules: required, must be a string, length 1–100 characters.
 */
function validateName(name) {
  const errors = [];

  if (name === undefined || name === null) {
    errors.push('name is required');
  } else if (typeof name !== 'string') {
    errors.push('name must be a string');
  } else if (name.length < 1) {
    errors.push('name must be at least 1 character long');
  } else if (name.length > 100) {
    errors.push('name must be at most 100 characters long');
  }

  return errors;
}

/**
 * Validates an email value.
 * Rules: required, must be a string, must match email format, max 254 characters.
 */
function validateEmail(email) {
  const errors = [];

  if (email === undefined || email === null) {
    errors.push('email is required');
  } else if (typeof email !== 'string') {
    errors.push('email must be a string');
  } else {
    if (!EMAIL_REGEX.test(email)) {
      errors.push('email must be a valid email address');
    }
    if (email.length > 254) {
      errors.push('email must be at most 254 characters long');
    }
  }

  return errors;
}

/**
 * Validates the request body for creating a user.
 * Both name and email are required.
 */
function validateCreateUser(body) {
  const errors = [];
  errors.push(...validateName(body.name));
  errors.push(...validateEmail(body.email));
  return errors;
}

/**
 * Validates the request body for updating a user.
 * At least one of name or email must be provided; present fields are fully validated.
 */
function validateUpdateUser(body) {
  const errors = [];
  const hasName = body.name !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name, email) must be provided for update');
    return errors;
  }

  if (hasName) {
    errors.push(...validateName(body.name));
  }
  if (hasEmail) {
    errors.push(...validateEmail(body.email));
  }

  return errors;
}

module.exports = {
  validateParamId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
};

