/**
 * Validation helper module.
 *
 * Each validator returns an array of error strings.  An empty array means the
 * data is valid.  Compose multiple validators with runValidators().
 */

'use strict';

// ---------------------------------------------------------------------------
// Primitive validators
// ---------------------------------------------------------------------------

/**
 * Assert that every field name listed in `fields` exists on `data` and is not
 * null / undefined / empty-string.
 *
 * @param {object} data
 * @param {string[]} fields
 * @returns {string[]} errors
 */
function validateRequired(data, fields) {
  const errors = [];
  for (const field of fields) {
    const value = data[field];
    if (value === undefined || value === null || value === '') {
      errors.push(`"${field}" is required`);
    }
  }
  return errors;
}

/**
 * Assert that `value` is a finite integer (or a string representation of one).
 *
 * @param {*} value
 * @param {string} fieldName  – used in the error message
 * @returns {string[]} errors
 */
function validateNumericId(value, fieldName = 'id') {
  if (value === undefined || value === null) return [];   // let validateRequired handle absence
  const parsed = Number(value);
  if (!Number.isInteger(parsed) || parsed <= 0) {
    return [`"${fieldName}" must be a positive integer`];
  }
  return [];
}

/**
 * Assert that `value` is a non-null string (not just typeof === 'string', but
 * also not an object / array / number that happens to be passed as a body field).
 *
 * @param {*} value
 * @param {string} fieldName
 * @returns {string[]} errors
 */
function validateString(value, fieldName) {
  if (value === undefined || value === null) return [];   // let validateRequired handle absence
  if (typeof value !== 'string') {
    return [`"${fieldName}" must be a string`];
  }
  return [];
}

/**
 * Assert that a string value's length is within [min, max] (inclusive).
 * Skips the check when the value is absent or not a string (other validators
 * handle those cases).
 *
 * @param {*} value
 * @param {string} fieldName
 * @param {number} min
 * @param {number} max
 * @returns {string[]} errors
 */
function validateStringLength(value, fieldName, min, max) {
  if (typeof value !== 'string') return [];
  if (value.length < min || value.length > max) {
    return [`"${fieldName}" must be between ${min} and ${max} characters`];
  }
  return [];
}

/**
 * Assert that `value` matches a broadly-accepted e-mail format.
 * Uses the RFC 5321 practical limit of 254 characters and a regex that covers
 * the overwhelming majority of real-world addresses.
 *
 * @param {*} value
 * @param {string} fieldName
 * @returns {string[]} errors
 */
function validateEmail(value, fieldName = 'email') {
  if (value === undefined || value === null) return [];
  if (typeof value !== 'string') return [];
  // Simple but robust email regex: local@domain.tld
  const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!EMAIL_RE.test(value)) {
    return [`"${fieldName}" must be a valid email address`];
  }
  return [];
}

// ---------------------------------------------------------------------------
// Composite validators for the User resource
// ---------------------------------------------------------------------------

/**
 * Validate the body of a POST /users request.
 * Required: name, email.
 *
 * @param {object} body
 * @returns {string[]} errors
 */
function validateCreateUser(body) {
  return [
    ...validateRequired(body, ['name', 'email']),
    ...validateString(body.name, 'name'),
    ...validateStringLength(body.name, 'name', 1, 100),
    ...validateString(body.email, 'email'),
    ...validateStringLength(body.email, 'email', 1, 254),
    ...validateEmail(body.email, 'email'),
  ];
}

/**
 * Validate the body of a PUT /users/:id request.
 * At least one of name / email must be supplied; both are optional but, when
 * present, must meet the same rules as on creation.
 *
 * @param {object} body
 * @returns {string[]} errors
 */
function validateUpdateUser(body) {
  const errors = [];

  if (body.name === undefined && body.email === undefined) {
    errors.push('at least one of "name" or "email" must be provided');
  }

  if (body.name !== undefined) {
    errors.push(...validateString(body.name, 'name'));
    errors.push(...validateStringLength(body.name, 'name', 1, 100));
  }

  if (body.email !== undefined) {
    errors.push(...validateString(body.email, 'email'));
    errors.push(...validateStringLength(body.email, 'email', 1, 254));
    errors.push(...validateEmail(body.email, 'email'));
  }

  return errors;
}

/**
 * Validate a route parameter that must be a positive-integer id.
 *
 * @param {string|*} paramValue  – value from req.params
 * @param {string} fieldName
 * @returns {string[]} errors
 */
function validateIdParam(paramValue, fieldName = 'id') {
  const errors = [
    ...validateRequired({ [fieldName]: paramValue }, [fieldName]),
    ...validateNumericId(paramValue, fieldName),
  ];
  return errors;
}

// ---------------------------------------------------------------------------
// Response helper
// ---------------------------------------------------------------------------

/**
 * If `errors` is non-empty, send a 400 JSON response listing every problem and
 * return `true` so the caller can bail out early.  Otherwise return `false`.
 *
 * @param {string[]} errors
 * @param {import('express').Response} res
 * @returns {boolean}
 */
function sendValidationErrors(errors, res) {
  if (errors.length === 0) return false;
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  validateRequired,
  validateNumericId,
  validateString,
  validateStringLength,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  validateIdParam,
  sendValidationErrors,
};

