/**
 * validation.js
 * Reusable input-validation helpers for Express route handlers.
 *
 * Every validate* function returns an array of human-readable error strings.
 * An empty array means the value is valid.
 * sendValidationError() is a convenience wrapper that writes the 400 response.
 */

'use strict';

// RFC 5321 / RFC 5322 practical email regex
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const NAME_MIN = 1;
const NAME_MAX = 100;
const EMAIL_MAX = 254; // per RFC 5321

/**
 * Validate a route/query parameter that must be a positive integer ID.
 *
 * @param {string|number} id - Raw value (usually req.params.id).
 * @returns {string[]} Validation errors (empty if valid).
 */
function validateId(id) {
  const errors = [];
  const numeric = Number(id);

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
  } else if (!Number.isFinite(numeric) || !Number.isInteger(numeric) || numeric <= 0) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate a `name` field value.
 *
 * @param {*} name       - Value from the request body.
 * @param {boolean} required - Whether the field must be present.
 * @returns {string[]} Validation errors (empty if valid).
 */
function validateName(name, required = true) {
  const errors = [];

  if (name === undefined || name === null) {
    if (required) errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  if (name.length < NAME_MIN) {
    errors.push(`name must be at least ${NAME_MIN} character`);
  } else if (name.length > NAME_MAX) {
    errors.push(`name must be at most ${NAME_MAX} characters`);
  }

  return errors;
}

/**
 * Validate an `email` field value.
 *
 * @param {*} email      - Value from the request body.
 * @param {boolean} required - Whether the field must be present.
 * @returns {string[]} Validation errors (empty if valid).
 */
function validateEmail(email, required = true) {
  const errors = [];

  if (email === undefined || email === null) {
    if (required) errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (email.length > EMAIL_MAX) {
    errors.push(`email must be at most ${EMAIL_MAX} characters`);
  } else if (!EMAIL_REGEX.test(email)) {
    errors.push('email must be a valid email address (e.g. user@example.com)');
  }

  return errors;
}

/**
 * Validate a complete user body (name + email).
 *
 * @param {object}  body          - req.body
 * @param {object}  [opts]
 * @param {boolean} [opts.requireAll=true] - When false, fields are optional
 *                                           (useful for PATCH).
 * @returns {string[]} All validation errors collected (empty if valid).
 */
function validateUserBody(body, { requireAll = true } = {}) {
  if (!body || typeof body !== 'object' || Array.isArray(body)) {
    return ['request body must be a JSON object'];
  }

  return [
    ...validateName(body.name, requireAll),
    ...validateEmail(body.email, requireAll),
  ];
}

/**
 * Send a 400 response with a structured validation-error payload.
 *
 * Response shape:
 *   { "error": "Validation failed", "details": ["...", "..."] }
 *
 * @param {import('express').Response} res
 * @param {string[]} errors - Non-empty array of error messages.
 * @returns The Express Response object (so callers can `return` it).
 */
function sendValidationError(res, errors) {
  return res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateUserBody,
  sendValidationError,
};

