// Validates: id must be a positive integer,
//            at least one of name or email must be provided,
//            each supplied field checked for type / length / format.
// ---------------------------------------------------------------------------
app.patch('/users/:id', (req, res) => {
  const idErrors = validateId(req.params.id);
  const bodyErrors = validatePatchUser(req.body);
  const allErrors = [...idErrors, ...bodyErrors];

  if (allErrors.length > 0) {
    return res.status(400).json(buildErrorResponse(allErrors));
  }

  const index = users.findIndex((u) => u.id === Number(req.params.id));
  if (index === -1) {
    return res.status(404).json({ error: 'User not found' });
  }

  if (req.body.name !== undefined) {
    users[index].name = req.body.name.trim();
  }
  if (req.body.email !== undefined) {
    users[index].email = req.body.email;
  }

  res.json(users[index]);
});

// ---------------------------------------------------------------------------
// DELETE /users/:id
// Validates: id must be a positive integer.
// ---------------------------------------------------------------------------
app.delete('/users/:id', (req, res) => {
  const idErrors = validateId(req.params.id);
  if (idErrors.length > 0) {
    return res.status(400).json(buildErrorResponse(idErrors));
  }

  const index = users.findIndex((u) => u.id === Number(req.params.id));
  if (index === -1) {
    return res.status(404).json({ error: 'User not found' });
  }

  const deleted = users.splice(index, 1)[0];
  res.json({ message: 'User deleted', user: deleted });
});

// ---------------------------------------------------------------------------

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

module.exports = app;

